import { useState } from "react";
import AdminNavbar from "../../components/UserNavbar/UserNavbar";
import "./Borrow.css";

export default function LibrarySearch() {
  const [searchQuery, setSearchQuery] = useState("");
  const [books, setBooks] = useState([
    { id: 1, title: "The Great Gatsby", author: "F. Scott Fitzgerald", borrowed: false },
    { id: 2, title: "To Kill a Mockingbird", author: "Harper Lee", borrowed: false },
    { id: 3, title: "1984", author: "George Orwell", borrowed: false },
  ]);

  const handleBorrow = (id) => {
    setBooks(books.map(book => 
      book.id === id ? { ...book, borrowed: !book.borrowed } : book
    ));
  };

  const filteredBooks = books.filter((book) =>
    book.title.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <div className="library-search-container">
      <AdminNavbar />
      <h1 className="library-search-title">Explore Books</h1>
      <input
        className="search-input"
        type="text"
        placeholder="Search for a book..."
        value={searchQuery}
        onChange={(e) => setSearchQuery(e.target.value)}
      />
      <h2 className="library-subtitle">Available Books</h2>
      {filteredBooks.length === 0 ? (
        <p className="empty-message">No books found</p>
      ) : (
        <ul className="book-list">
          {filteredBooks.map((book) => (
            <li key={book.id} className="book-item">
              <strong>
                {book.title} <span>by {book.author}</span>
              </strong>
              <button 
                className={`borrow-button ${book.borrowed ? "borrowed" : ""}`} 
                onClick={() => handleBorrow(book.id)}
              >
                {book.borrowed ? "Borrowed" : "Borrow"}
              </button>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}
